prompt --application/shared_components/security/authorizations/admin_only
begin
wwv_flow_imp_shared.create_security_scheme(
 p_id=>wwv_flow_imp.id(154687611987698344582)
,p_name=>'ADMIN_ONLY'
,p_scheme_type=>'NATIVE_FUNCTION_BODY'
,p_attribute_01=>wwv_flow_string.join(wwv_flow_t_varchar2(
'DECLARE',
'    v_count NUMBER;',
'BEGIN',
'    SELECT COUNT(*)',
'    INTO v_count',
'    FROM SYSTEM_USER su, ADMIN a',
'    WHERE su.user_id = a.user_id',
'      AND LOWER(su.email) = LOWER(:APP_USER);',
'',
'    IF v_count > 0 THEN',
'        RETURN TRUE;',
'    ELSE',
'        RETURN FALSE;',
'    END IF;',
'END;'))
,p_version_scn=>15752270952737
,p_caching=>'BY_USER_BY_SESSION'
);
end;
/
prompt --application/shared_components/security/authorizations/customer_or_admin_access
begin
wwv_flow_imp_shared.create_security_scheme(
 p_id=>wwv_flow_imp.id(154886057106623280906)
,p_name=>'Customer or Admin Access'
,p_scheme_type=>'NATIVE_FUNCTION_BODY'
,p_attribute_01=>wwv_flow_string.join(wwv_flow_t_varchar2(
'DECLARE',
'    v_count NUMBER;',
'BEGIN',
'    SELECT COUNT(*)',
'    INTO v_count',
'    FROM SYSTEM_USER su, CUSTOMER c',
'    WHERE su.user_id = c.user_id',
'      AND UPPER(su.email) = UPPER(:APP_USER);',
'',
'    IF v_count > 0 THEN',
'        RETURN TRUE;',
'    END IF;',
'',
'    SELECT COUNT(*)',
'    INTO v_count',
'    FROM SYSTEM_USER su, ADMIN a',
'    WHERE su.user_id = a.user_id',
'      AND UPPER(su.email) = UPPER(:APP_USER);',
'',
'    IF v_count > 0 THEN',
'        RETURN TRUE;',
'    END IF;',
'',
'    RETURN FALSE;',
'END;'))
,p_version_scn=>15752718470856
,p_caching=>'BY_USER_BY_SESSION'
);
end;
/
prompt --application/shared_components/security/authorizations/trader_or_admin_access
begin
wwv_flow_imp_shared.create_security_scheme(
 p_id=>wwv_flow_imp.id(154886870783124959718)
,p_name=>'Trader or Admin Access'
,p_scheme_type=>'NATIVE_FUNCTION_BODY'
,p_attribute_01=>wwv_flow_string.join(wwv_flow_t_varchar2(
'DECLARE',
'    v_count NUMBER;',
'BEGIN',
'    -- Check if user is trader',
'    SELECT COUNT(*)',
'    INTO v_count',
'    FROM SYSTEM_USER su, TRADER t',
'    WHERE su.user_id = t.user_id',
'      AND UPPER(su.email) = UPPER(:APP_USER);',
'',
'    IF v_count > 0 THEN',
'        RETURN TRUE;',
'    END IF;',
'',
'    -- Check if user is admin',
'    SELECT COUNT(*)',
'    INTO v_count',
'    FROM SYSTEM_USER su, ADMIN a',
'    WHERE su.user_id = a.user_id',
'      AND UPPER(su.email) = UPPER(:APP_USER);',
'',
'    IF v_count > 0 THEN',
'        RETURN TRUE;',
'    END IF;',
'',
'    RETURN FALSE;',
'END;'))
,p_version_scn=>15752722515281
,p_caching=>'BY_USER_BY_SESSION'
);
end;
