wwv_flow_imp_page.create_jet_chart_series(
 p_id=>wwv_flow_imp.id(154647030528462115322)
,p_chart_id=>wwv_flow_imp.id(154647030456835115321)
,p_seq=>10
,p_name=>'New'
,p_data_source_type=>'SQL'
,p_data_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
'SELECT ',
'    cs.collection_time AS label,',
'    COUNT(',
'        CASE ',
'            WHEN s.trader_id = NVL(',
'                :P2_TRADER_ID,',
'                (',
'                    SELECT user_id',
'                    FROM system_user',
'                    WHERE UPPER(email) = UPPER(:APP_USER)',
'                )',
'            ) THEN o.order_id',
'        END',
'    ) AS value,',
'    CASE ',
'        WHEN cs.collection_time = ''10-13'' THEN ''#3498db''',
'        WHEN cs.collection_time = ''13-16'' THEN ''#f39c12''',
'        WHEN cs.collection_time = ''16-19'' THEN ''#2ecc71''',
'    END AS color',
'FROM collection_slot cs',
'LEFT JOIN orders o ',
'    ON cs.slot_id = o.slot_id',
'LEFT JOIN order_item oi ',
'    ON o.order_id = oi.order_id',
'LEFT JOIN product p ',
'    ON oi.product_id = p.product_id',
'LEFT JOIN shop s ',
'    ON p.shop_id = s.shop_id',
'WHERE cs.collection_time IN (''10-13'',''13-16'',''16-19'')',
