wwv_flow_imp_page.create_report_region(
 p_id=>wwv_flow_imp.id(154341990056336652207)
,p_name=>'Recent Orders report'
,p_title=>'Recent Orders'
,p_region_name=>'recent_orders'
,p_template=>4072358936313175081
,p_display_sequence=>50
,p_region_css_classes=>'dash-panel dash-table-panel'
,p_region_sub_css_classes=>'dash-panel dash-table-panel'
,p_region_template_options=>'#DEFAULT#:t-Region--scrollBody'
,p_component_template_options=>'#DEFAULT#:t-Report--altRowsDefault:t-Report--rowHighlight'
,p_grid_column_span=>6
,p_source_type=>'NATIVE_SQL_REPORT'
,p_query_type=>'SQL'
,p_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
'SELECT *',
'FROM (',
'    SELECT ',
'        o.order_id,',
'        o.order_date,',
'        SUM(oi.quantity * p.price) AS total_amount,',
'',
'        CASE ',
'            WHEN o.status = ''COMPLETED'' THEN ',
'                ''<span style="background:#2ecc71;color:white;padding:4px 10px;border-radius:10px;">COMPLETED</span>''',
'',
'            WHEN o.status = ''PENDING'' THEN ',
'                ''<span style="background:#f39c12;color:white;padding:4px 10px;border-radius:10px;">PENDING</span>''',
'',
'            WHEN o.status = ''CONFIRMED'' THEN ',
'                ''<span style="background:#3498db;color:white;padding:4px 10px;border-radius:10px;">CONFIRMED</span>''',
'',
'            WHEN o.status = ''CANCELLED'' THEN ',
'                ''<span style="background:#e74c3c;color:white;padding:4px 10px;border-radius:10px;">CANCELLED</span>''',
'',
'            ELSE o.status',
'        END AS status',
'',
'    FROM orders o',
'    JOIN order_item oi ',
'        ON o.order_id = oi.order_id',
'    JOIN product p ',
'        ON oi.product_id = p.product_id',
'    GROUP BY o.order_id, o.order_date, o.status',
'    ORDER BY o.order_date DESC',
')',
'WHERE ROWNUM <= 5;'))
,p_ajax_enabled=>'Y'
,p_lazy_loading=>false
,p_query_row_template=>2538654340625403440
,p_query_num_rows=>5
,p_query_options=>'DERIVED_REPORT_COLUMNS'
,p_query_num_rows_type=>'NEXT_PREVIOUS_LINKS'
,p_pagination_display_position=>'BOTTOM_RIGHT'
,p_csv_output=>'N'
,p_prn_output=>'N'
,p_sort_null=>'L'
,p_plug_query_strip_html=>'N'
);
