 p_id=>wwv_flow_imp.id(154341991316326652220)
,p_plug_name=>'Collection Time Distribution'
,p_title=>'Collection Time Distribution'
,p_region_css_classes=>'dash-slot-cards'
,p_region_template_options=>'#DEFAULT#:t-Region--scrollBody'
,p_component_template_options=>'#DEFAULT#'
,p_plug_template=>4072358936313175081
,p_plug_display_sequence=>80
,p_plug_grid_column_span=>12
,p_query_type=>'SQL'
,p_plug_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
'SELECT ',
'    CASE ',
'        WHEN collection_time = ''10-13'' THEN ''Morning (10-13)''',
'        WHEN collection_time = ''13-16'' THEN ''Afternoon (13-16)''',
'        WHEN collection_time = ''16-19'' THEN ''Evening (16-19)''',
'    END AS TITLE,',
'',
'    COUNT(*) AS VALUE,',
'',
'    CASE ',
unistr('        WHEN collection_time = ''10-13'' THEN ''\2600'''),
unistr('        WHEN collection_time = ''13-16'' THEN ''\2601'''),
unistr('        WHEN collection_time = ''16-19'' THEN ''\D83C\DF19'''),
'    END AS BODY',
'',
'FROM COLLECTION_SLOT',
'GROUP BY collection_time',
'ORDER BY collection_time;'))
,p_lazy_loading=>false
,p_plug_source_type=>'NATIVE_CARDS'
,p_plug_query_num_rows_type=>'SCROLL'
,p_show_total_row_count=>false
);
