wwv_flow_imp_page.create_page_plug(
 p_id=>wwv_flow_imp.id(155793184415340116713)
,p_plug_name=>'Customer Management'
,p_region_template_options=>'#DEFAULT#:t-IRR-region--hideHeader js-addHiddenHeadingRoleDesc'
,p_plug_template=>2100526641005906379
,p_plug_display_sequence=>30
,p_query_type=>'SQL'
,p_plug_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
'SELECT ',
'    su.user_id AS ID,',
'    su.name,',
'    su.email,',
'    su.created_at AS REGISTERED,',
'    NVL(o.order_count, 0) AS ORDERS,',
'    CASE',
'        WHEN su.status = ''SUSPENDED'' THEN ''SUSPENDED''',
'        ELSE ''ACTIVE''',
'    END AS STATUS,',
'    CASE',
'        WHEN su.status = ''SUSPENDED'' THEN ''#f8d7da''',
'        ELSE ''#d4edda''',
'    END AS STATUS_BG,',
'    CASE',
'        WHEN su.status = ''SUSPENDED'' THEN ''#721c24''',
'        ELSE ''#155724''',
'    END AS STATUS_COLOR',
'FROM SYSTEM_USER su',
'JOIN CUSTOMER c ',
'    ON su.user_id = c.user_id',
'LEFT JOIN (',
'    SELECT customer_id, COUNT(*) AS order_count',
'    FROM ORDERS',
'    GROUP BY customer_id',
') o ',
'    ON su.user_id = o.customer_id',
'WHERE (',
'    :P6_STATUS = ''ALL''',
'    OR :P6_STATUS IS NULL',
'    OR :P6_STATUS = CASE',
'        WHEN su.status = ''SUSPENDED'' THEN ''SUSPENDED''',
'        ELSE ''ACTIVE''',
'    END',
')',
'ORDER BY su.user_id'))
,p_plug_source_type=>'NATIVE_IR'
,p_prn_page_header=>'Customer Management'
);
