,p_region_template_options=>'#DEFAULT#:t-IRR-region--hideHeader js-addHiddenHeadingRoleDesc'
,p_plug_template=>2100526641005906379
,p_plug_display_sequence=>20
,p_query_type=>'SQL'
,p_plug_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
'SELECT ',
'    su.user_id AS id,',
'    su.name,',
'    su.email,',
'    su.phone_no,',
'    su.address,',
'    t.business_name,',
'    t.license_no,',
'    su.created_at AS registered,',
'',
'    CASE',
'        WHEN su.user_id IN (4, 5) THEN ''ACTIVE''',
'        ELSE ''SUSPENDED''',
'    END AS status,',
'',
'    CASE',
'        WHEN su.user_id IN (4, 5) THEN ''#d4edda''',
'        ELSE ''#f8d7da''',
'    END AS status_bg,',
'',
'    CASE',
'        WHEN su.user_id IN (4, 5) THEN ''#155724''',
'        ELSE ''#721c24''',
'    END AS status_color',
'',
'FROM SYSTEM_USER su',
'JOIN TRADER t',
'    ON su.user_id = t.user_id',
'',
'WHERE (',
'    :P8_STATUS = ''ALL''',
'    OR :P8_STATUS IS NULL',
'    OR :P8_STATUS = CASE',
'        WHEN su.user_id IN (4, 5) THEN ''ACTIVE''',
'        ELSE ''SUSPENDED''',
'    END',
')',
'',
'ORDER BY su.user_id'))
,p_plug_source_type=>'NATIVE_IR'
,p_ajax_items_to_submit=>'P8_STATUS'
,p_prn_page_header=>'Trader Management'
);
