wwv_flow_imp_page.create_page_process(
 p_id=>wwv_flow_imp.id(154647032401102115341)
,p_process_sequence=>20
,p_process_point=>'AFTER_SUBMIT'
,p_process_type=>'NATIVE_PLSQL'
,p_process_name=>'Add To Cart Process'
,p_process_sql_clob=>wwv_flow_string.join(wwv_flow_t_varchar2(
'DECLARE',
'    v_user_id NUMBER;',
'    v_cart_id NUMBER;',
'    v_count   NUMBER;',
'BEGIN',
'    -- Get logged-in user id',
'    BEGIN',
'        SELECT user_id',
'        INTO v_user_id',
'        FROM system_user',
'        WHERE UPPER(email) = UPPER(:APP_USER);',
'    EXCEPTION',
'        WHEN NO_DATA_FOUND THEN',
'            RAISE_APPLICATION_ERROR(-20002, ''Logged-in user not found in SYSTEM_USER'');',
'    END;',
'',
'    -- Get existing cart or create one',
'    BEGIN',
'        SELECT cart_id',
'        INTO v_cart_id',
'        FROM cart',
'        WHERE customer_id = v_user_id;',
'    EXCEPTION',
'        WHEN NO_DATA_FOUND THEN',
'            INSERT INTO cart (',
'                cart_id,',
'                created_date,',
'                status,',
'                customer_id',
'            )',
'            VALUES (',
'                cart_seq.NEXTVAL,',
'                SYSDATE,',
'                ''Active'',',
'                v_user_id',
'            )',
'            RETURNING cart_id INTO v_cart_id;',
'    END;',
'',
'    -- If product already in cart, increase quantity',
'    SELECT COUNT(*)',
'    INTO v_count',
'    FROM cart_item',
'    WHERE cart_id = v_cart_id',
'      AND product_id = :P10_PRODUCT_ID;',
'',
'    IF v_count > 0 THEN',
'        UPDATE cart_item',
'        SET quantity = quantity + 1',
'        WHERE cart_id = v_cart_id',
'          AND product_id = :P10_PRODUCT_ID;',
'    ELSE',
'        INSERT INTO cart_item (',
'            cart_item_id,',
'            product_id,',
'            quantity,',
'            price,',
'            cart_id',
'        )',
'        VALUES (',
'            cart_item_seq.NEXTVAL,',
'            :P10_PRODUCT_ID,',
'            1,',
'            :P10_PRICE,',
'            v_cart_id',
'        );',
'    END IF;',
'END;'))
,p_process_clob_language=>'PLSQL'
,p_error_display_location=>'INLINE_IN_NOTIFICATION'
,p_process_when=>'Add To Cart'
,p_process_when_type=>'REQUEST_EQUALS_CONDITION'
,p_internal_uid=>154647032401102115341
);
