wwv_flow_imp_page.create_page_process(
 p_id=>wwv_flow_imp.id(154828408734853379908)
,p_process_sequence=>10
,p_process_point=>'AFTER_SUBMIT'
,p_process_type=>'NATIVE_PLSQL'
,p_process_name=>'Insert Order'
,p_process_sql_clob=>wwv_flow_string.join(wwv_flow_t_varchar2(
'DECLARE',
'    v_user_id NUMBER;',
'    v_cart_id NUMBER;',
'    v_total   NUMBER;',
'BEGIN',
'    SELECT user_id',
'    INTO v_user_id',
'    FROM system_user',
'    WHERE UPPER(email) = UPPER(:APP_USER);',
'',
'    SELECT cart_id',
'    INTO v_cart_id',
'    FROM cart',
'    WHERE customer_id = v_user_id;',
'',
'    SELECT NVL(SUM(ci.quantity * ci.price), 0)',
'    INTO v_total',
'    FROM cart_item ci',
'    WHERE ci.cart_id = v_cart_id;',
'',
'    IF v_total = 0 THEN',
'        RAISE_APPLICATION_ERROR(-20001, ''Cart is empty'');',
'    END IF;',
'',
'    INSERT INTO "ORDER" (',
'        order_id,',
'        order_date,',
'        total_price,',
'        status,',
'        customer_id',
'    )',
'    VALUES (',
'        order_seq.NEXTVAL,',
'        SYSDATE,',
'        v_total,',
'        ''Pending'',',
'        v_user_id',
'    );',
'END;'))
,p_process_clob_language=>'PLSQL'
,p_error_display_location=>'INLINE_IN_NOTIFICATION'
,p_process_when=>'PLACE_ORDER'
,p_process_when_type=>'REQUEST_EQUALS_CONDITION'
,p_internal_uid=>154828408734853379908
);
wwv_flow_imp_page.create_page_process(
 p_id=>wwv_flow_imp.id(154828409026875379911)
,p_process_sequence=>20
,p_process_point=>'AFTER_SUBMIT'
,p_process_type=>'NATIVE_PLSQL'
,p_process_name=>'Insert Payment'
,p_process_sql_clob=>wwv_flow_string.join(wwv_flow_t_varchar2(
'DECLARE',
'    v_user_id  NUMBER;',
'    v_order_id NUMBER;',
'    v_total    NUMBER;',
'BEGIN',
'    SELECT user_id',
'    INTO v_user_id',
'    FROM system_user',
'    WHERE UPPER(email) = UPPER(:APP_USER);',
'',
'    SELECT MAX(order_id)',
'    INTO v_order_id',
'    FROM "ORDER"',
'    WHERE customer_id = v_user_id;',
'',
'    SELECT total_price',
'    INTO v_total',
'    FROM "ORDER"',
'    WHERE order_id = v_order_id;',
'',
'    INSERT INTO payment (',
'        payment_id,',
'        payment_date,',
'        amount,',
'        payment_status,',
'        order_id,',
'        method_id,',
'        user_id',
'    )',
'    VALUES (',
'        payment_seq.NEXTVAL,',
'        SYSDATE,',
'        v_total,',
'        ''Paid'',',
'        v_order_id,',
'        :P12_PAYMENT_METHOD,',
'        v_user_id',
'    );',
'END;'))
,p_process_clob_language=>'PLSQL'
,p_error_display_location=>'INLINE_IN_NOTIFICATION'
,p_process_when=>'PLACE_ORDER'
,p_process_when_type=>'REQUEST_EQUALS_CONDITION'
,p_internal_uid=>154828409026875379911
);
wwv_flow_imp_page.create_page_process(
 p_id=>wwv_flow_imp.id(154828409143313379912)
,p_process_sequence=>30
,p_process_point=>'AFTER_SUBMIT'
,p_process_type=>'NATIVE_PLSQL'
,p_process_name=>'Clear Cart'
,p_process_sql_clob=>wwv_flow_string.join(wwv_flow_t_varchar2(
'DECLARE',
'    v_user_id NUMBER;',
'    v_cart_id NUMBER;',
'BEGIN',
'    SELECT user_id',
'    INTO v_user_id',
'    FROM system_user',
'    WHERE UPPER(email) = UPPER(:APP_USER);',
'',
'    SELECT cart_id',
'    INTO v_cart_id',
'    FROM cart',
'    WHERE customer_id = v_user_id;',
'',
'    DELETE FROM cart_item',
'    WHERE cart_id = v_cart_id;',
'END;'))
,p_process_clob_language=>'PLSQL'
,p_error_display_location=>'INLINE_IN_NOTIFICATION'
,p_process_when=>'PLACE_ORDER'
,p_process_when_type=>'REQUEST_EQUALS_CONDITION'
,p_internal_uid=>154828409143313379912
);
end;
