 p_id=>wwv_flow_imp.id(159456587146367476172)
,p_plug_name=>'Reviews'
,p_region_template_options=>'#DEFAULT#:t-IRR-region--hideHeader js-addHiddenHeadingRoleDesc'
,p_plug_template=>2100526641005906379
,p_plug_display_sequence=>10
,p_query_type=>'SQL'
,p_plug_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
'SELECT',
'    r.review_id,',
'    r.rating,',
'    r.comment_text,',
'    r.review_date,',
'    su.name AS customer_name,',
'    p.product_name,',
'    s.shop_name,',
'    CASE',
'        WHEN r.status = ''APPROVED'' THEN ''<span class="t-Badge t-Badge--success">APPROVED</span>''',
'        WHEN r.status = ''REJECTED'' THEN ''<span class="t-Badge t-Badge--danger">REJECTED</span>''',
'        ELSE ''<span class="t-Badge t-Badge--warning">PENDING</span>''',
'    END AS status,',
'    CASE',
'        WHEN r.status = ''PENDING'' THEN',
'            ''<button class="t-Button t-Button--success t-Button--small"',
'             onclick="apex.submit(''''APPROVE_'' || r.review_id || ''''''); return false;">',
'             Approve</button>''',
'        ELSE NULL',
'    END AS approve_btn,',
'    CASE',
'        WHEN r.status = ''PENDING'' THEN',
'            ''<button class="t-Button t-Button--danger t-Button--small"',
'             onclick="apex.submit(''''REJECT_'' || r.review_id || ''''''); return false;">',
'             Reject</button>''',
'        ELSE NULL',
'    END AS reject_btn',
'FROM review r',
'JOIN customer c',
'    ON r.customer_id = c.user_id',
'JOIN system_user su',
'    ON c.user_id = su.user_id',
'JOIN product p',
'    ON r.product_id = p.product_id',
'JOIN shop s',
'    ON p.shop_id = s.shop_id',
'ORDER BY r.review_date DESC'))
,p_plug_source_type=>'NATIVE_IR'
,p_prn_page_header=>'Reviews'
);
