 p_id=>wwv_flow_imp.id(156418095225250619946)
,p_plug_name=>'Breadcrumb'
,p_region_template_options=>'#DEFAULT#:t-BreadcrumbRegion--useBreadcrumbTitle'
,p_component_template_options=>'#DEFAULT#'
,p_plug_template=>2531463326621247859
,p_plug_display_sequence=>10
,p_plug_display_point=>'REGION_POSITION_01'
,p_menu_id=>wwv_flow_imp.id(154328629499101803321)
,p_plug_source_type=>'NATIVE_BREADCRUMB'
,p_menu_template_id=>4072363345357175094
);
wwv_flow_imp_page.create_page_plug(
 p_id=>wwv_flow_imp.id(156418095948440619948)
,p_plug_name=>'Orders Report'
,p_region_template_options=>'#DEFAULT#:t-IRR-region--hideHeader js-addHiddenHeadingRoleDesc'
,p_plug_template=>2100526641005906379
,p_plug_display_sequence=>10
,p_query_type=>'SQL'
,p_plug_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
'SELECT ',
'    o.order_id,',
'    su.name AS customer_name,',
'    p.product_name,',
'    oi.quantity,',
'    (oi.quantity * p.price) AS total_amount,',
'    cs.collection_time,',
'    o.order_date,',
'    CASE ',
'        WHEN o.status = ''PENDING'' THEN ',
'            ''<span style="color:white;background:orange;padding:4px 8px;border-radius:8px;">PENDING</span>''',
'        WHEN o.status = ''CONFIRMED'' THEN ',
'            ''<span style="color:white;background:blue;padding:4px 8px;border-radius:8px;">CONFIRMED</span>''',
'        WHEN o.status = ''COMPLETED'' THEN ',
'            ''<span style="color:white;background:green;padding:4px 8px;border-radius:8px;">COMPLETED</span>''',
'        ELSE o.status',
'    END AS status',
'FROM orders o',
'JOIN order_item oi ',
'    ON o.order_id = oi.order_id',
'JOIN product p ',
'    ON oi.product_id = p.product_id',
'JOIN system_user su ',
'    ON o.customer_id = su.user_id',
'JOIN collection_slot cs',
'    ON o.slot_id = cs.slot_id',
'JOIN shop s ',
'    ON p.shop_id = s.shop_id',
'JOIN trader t ',
'    ON s.trader_id = t.user_id',
'JOIN system_user tu ',
'    ON t.user_id = tu.user_id',
'WHERE t.user_id = NVL(',
'    :P26_TRADER_ID,',
'    (',
'        SELECT user_id',
'        FROM system_user',
'        WHERE LOWER(email) = LOWER(:APP_USER)',
'    )',
')',
'ORDER BY o.order_date DESC'))
,p_plug_source_type=>'NATIVE_IR'
,p_prn_page_header=>'Orders Report'
);
