,p_component_template_options=>'#DEFAULT#'
,p_plug_template=>2531463326621247859
,p_plug_display_sequence=>10
,p_plug_display_point=>'REGION_POSITION_01'
,p_menu_id=>wwv_flow_imp.id(154328629499101803321)
,p_plug_source_type=>'NATIVE_BREADCRUMB'
,p_menu_template_id=>4072363345357175094
);
wwv_flow_imp_page.create_page_plug(
 p_id=>wwv_flow_imp.id(156422019013114300756)
,p_plug_name=>'Monthly Sales Report'
,p_region_template_options=>'#DEFAULT#:t-IRR-region--hideHeader js-addHiddenHeadingRoleDesc'
,p_plug_template=>2100526641005906379
,p_plug_display_sequence=>40
,p_query_type=>'SQL'
,p_plug_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
'SELECT ',
'    p.product_name,',
'    COUNT(DISTINCT o.order_id) AS total_orders,',
'    SUM(oi.quantity) AS total_quantity_sold,',
'    SUM(oi.quantity * p.price) AS total_income',
'FROM product p',
'JOIN order_item oi ON p.product_id = oi.product_id',
'JOIN orders o ON oi.order_id = o.order_id',
'JOIN shop s ON p.shop_id = s.shop_id',
'WHERE s.trader_id = NVL(',
'    :P28_TRADER_ID,',
'    (',
'        SELECT user_id',
'        FROM system_user',
'        WHERE LOWER(email) = LOWER(:APP_USER)',
'    )',
')',
'AND (',
'    :P28_MONTH IS NULL',
'    OR TO_CHAR(o.order_date, ''MM-YYYY'') = :P28_MONTH',
')',
'GROUP BY p.product_name',
'ORDER BY total_income DESC;'))
,p_plug_source_type=>'NATIVE_IR'
,p_ajax_items_to_submit=>'P28_SORT_BY, P28_MONTH'
,p_prn_page_header=>'Monthly Sales Report'
);
